import{_ as a,o as i,c as t,a2 as o}from"./chunks/framework.C69UpXSI.js";const u=JSON.parse('{"title":"Interfaccia terminale (TUI)","description":"","frontmatter":{},"headers":[],"relativePath":"it/utilizzo/index.md","filePath":"it/utilizzo/index.md"}'),s={name:"it/utilizzo/index.md"};function n(r,e,l,d,p,c){return i(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="interfaccia-terminale-tui" tabindex="-1">Interfaccia terminale (TUI) <a class="header-anchor" href="#interfaccia-terminale-tui" aria-label="Permalink to &quot;Interfaccia terminale (TUI)&quot;">​</a></h1><p>Usare TurboDev nel terminale.</p><h2 id="avviare-una-sessione" tabindex="-1">Avviare una sessione <a class="header-anchor" href="#avviare-una-sessione" aria-label="Permalink to &quot;Avviare una sessione&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /percorso/del/tuo/progetto</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">turbodev</span></span></code></pre></div><p>TurboDev apre una sessione interattiva nel terminale con:</p><ul><li><strong>Banner</strong> — Logo ASCII art, stato di AGENTS.md e agente corrente (visibile per 5 secondi)</li><li><strong>Area chat</strong> — Cronologia della conversazione</li><li><strong>Barra di input</strong> — Mostra il nome dell&#39;agente corrente, digita qui i tuoi messaggi</li><li><strong>Barra di stato</strong> — Modello, agente, utilizzo token, costo, indicatore di elaborazione</li></ul><h2 id="la-barra-di-stato" tabindex="-1">La barra di stato <a class="header-anchor" href="#la-barra-di-stato" aria-label="Permalink to &quot;La barra di stato&quot;">​</a></h2><p>La barra di stato in basso mostra:</p><table tabindex="0"><thead><tr><th>Elemento</th><th>Descrizione</th></tr></thead><tbody><tr><td>ID modello</td><td>Modello LLM corrente</td></tr><tr><td>Nome agente</td><td>Agente corrente con il suo colore</td></tr><tr><td>Utilizzo token</td><td><code>X.XXK/YK</code> — token usati / dimensione finestra di contesto</td></tr><tr><td>Costo</td><td>Costo cumulativo della sessione (es. <code>$0.0023</code>)</td></tr><tr><td>Spinner</td><td>Animazione braille mentre l&#39;AI sta elaborando</td></tr></tbody></table><h3 id="indicatore-utilizzo-token" tabindex="-1">Indicatore utilizzo token <a class="header-anchor" href="#indicatore-utilizzo-token" aria-label="Permalink to &quot;Indicatore utilizzo token&quot;">​</a></h3><p>L&#39;utilizzo dei token è codificato per colore:</p><table tabindex="0"><thead><tr><th>Colore</th><th>Significato</th></tr></thead><tbody><tr><td>Verde</td><td>Sotto il 50% della finestra di contesto</td></tr><tr><td>Giallo</td><td>50%–75% della finestra di contesto</td></tr><tr><td>Rosso</td><td>Sopra il 75% — l&#39;auto-compattazione si attiva all&#39;85%</td></tr></tbody></table><h3 id="tracciamento-dei-costi" tabindex="-1">Tracciamento dei costi <a class="header-anchor" href="#tracciamento-dei-costi" aria-label="Permalink to &quot;Tracciamento dei costi&quot;">​</a></h3><p>Il costo viene calcolato in tempo reale in base al prezzo per token del modello da OpenRouter. Si accumula su tutti i messaggi della sessione e viene salvato quando la sessione viene persistita.</p><h2 id="colori-degli-agenti" tabindex="-1">Colori degli agenti <a class="header-anchor" href="#colori-degli-agenti" aria-label="Permalink to &quot;Colori degli agenti&quot;">​</a></h2><p>Ogni agente ha un colore distinto nella barra di stato:</p><table tabindex="0"><thead><tr><th>Agente</th><th>Colore</th></tr></thead><tbody><tr><td>editor</td><td>Ciano</td></tr><tr><td>plan</td><td>Giallo</td></tr></tbody></table><p>Gli agenti personalizzati possono definire il proprio colore.</p><h2 id="indicatore-di-elaborazione" tabindex="-1">Indicatore di elaborazione <a class="header-anchor" href="#indicatore-di-elaborazione" aria-label="Permalink to &quot;Indicatore di elaborazione&quot;">​</a></h2><p>Quando l&#39;AI sta elaborando, uno spinner braille si anima nella barra di stato e la risposta appare in tempo reale nell&#39;area chat — vedrai il testo comparire parola per parola mentre viene generato:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>⠋ AI sta pensando...</span></span></code></pre></div><p>Se l&#39;AI chiama uno strumento (es. <code>read_file</code>), il testo streaming si azzera temporaneamente e riprende una volta elaborato il risultato. Questo ti dà un feedback immediato che l&#39;agente sta lavorando attivamente.</p><h2 id="richieste-di-permesso" tabindex="-1">Richieste di permesso <a class="header-anchor" href="#richieste-di-permesso" aria-label="Permalink to &quot;Richieste di permesso&quot;">​</a></h2><p>Quando un agente ha bisogno di approvazione (es. l&#39;agente plan sta modificando un file), il prompt appare anche mentre l&#39;AI sta elaborando. Puoi rispondere immediatamente:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>? Consentire edit_file?</span></span>
<span class="line"><span>  Comando: modifica di AGENTS.md</span></span>
<span class="line"><span>  [y/n]</span></span></code></pre></div><p>Digita <code>y</code> per consentire, <code>n</code> per negare.</p><h2 id="richieste-di-domanda" tabindex="-1">Richieste di domanda <a class="header-anchor" href="#richieste-di-domanda" aria-label="Permalink to &quot;Richieste di domanda&quot;">​</a></h2><p>Gli agenti possono farti domande:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>? Quale framework di test preferisci?</span></span>
<span class="line"><span>  1. vitest</span></span>
<span class="line"><span>  2. jest</span></span></code></pre></div><p>Digita la tua risposta e premi Invio.</p><h2 id="persistenza-delle-sessioni" tabindex="-1">Persistenza delle sessioni <a class="header-anchor" href="#persistenza-delle-sessioni" aria-label="Permalink to &quot;Persistenza delle sessioni&quot;">​</a></h2><p>Quando avvii TurboDev e esiste una sessione precedente, ti verrà chiesto:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Resume previous session?</span></span>
<span class="line"><span>  La mia funzionalità (4 min fa, 12 messaggi)</span></span>
<span class="line"><span>  [y/n]</span></span></code></pre></div><p>Premi <code>y</code> per ripristinare la sessione precedente, oppure <code>n</code> per iniziare da zero. Le sessioni vengono salvate automaticamente dopo ogni scambio di messaggi in <code>.turbodev/sessions/</code>.</p><h2 id="interrompere-le-richieste" tabindex="-1">Interrompere le richieste <a class="header-anchor" href="#interrompere-le-richieste" aria-label="Permalink to &quot;Interrompere le richieste&quot;">​</a></h2><p>Mentre l&#39;AI sta elaborando (spinner visibile), puoi premere <strong>Escape</strong> per cancellare la richiesta immediatamente. La barra di input è nascosta durante l&#39;elaborazione per evitare messaggi sovrapposti.</p><h2 id="flusso-di-lavoro" tabindex="-1">Flusso di lavoro <a class="header-anchor" href="#flusso-di-lavoro" aria-label="Permalink to &quot;Flusso di lavoro&quot;">​</a></h2><ol><li>Digita il tuo messaggio e premi Invio</li><li>L&#39;AI elabora e risponde (con streaming)</li><li>Se sono necessari strumenti, vengono eseguiti automaticamente o chiedono permesso</li><li>La risposta appare nell&#39;area chat</li><li>Ripeti</li></ol><h2 id="prossimi-passi" tabindex="-1">Prossimi passi <a class="header-anchor" href="#prossimi-passi" aria-label="Permalink to &quot;Prossimi passi&quot;">​</a></h2><ul><li><a href="/turbodev/it/utilizzo/comandi.html">Comandi</a></li><li><a href="/turbodev/it/utilizzo/scorciatoie.html">Scorciatoie da tastiera</a></li></ul>`,40)])])}const m=a(s,[["render",n]]);export{u as __pageData,m as default};
